public class Pipeline {
    public static void main(String[] args) {
        double original = 1000.0;
        double afterDiscount = applyDiscount(original, 10);
        double finalPrice = applyTax(afterDiscount, 18);

        System.out.println("Original: " + original);
        System.out.println("After discount: " + afterDiscount);
        System.out.println("Final (with tax): " + finalPrice);
    }

    public static double applyDiscount(double price, double percent) {
        return price - (price * percent / 100);
    }

    public static double applyTax(double price, double taxPercent) {
        return price + (price * taxPercent / 100);
    }
}

public class SafeDivider {
    public static void main(String[] args) {
        System.out.println("10.0 / 2.0 = " + divide(10, 2));
        System.out.println("15.0 / 0.0 = " + divide(15, 0));
        System.out.println("20.0 / 5.0 = " + divide(20, 5));
    }

    public static double divide(double a, double b) {
        if (b == 0) {
            return 0;
        }
        return a / b;
    }
}

public class Categorizer {
    public static void main(String[] args) {
        System.out.println("Score 95: " + getCategory(95));
        System.out.println("Score 80: " + getCategory(80));
        System.out.println("Score 65: " + getCategory(65));
