public class MathUtils {
    public static void main(String[] args) {
        System.out.println("max(5, 10): " + max(5, 10));
        System.out.println("min(5, 10): " + min(5, 10));
        System.out.println("absolute(-7): " + absolute(-7));
        System.out.println("average(10, 20, 30): " + average(10, 20, 30));
    }

    public static int max(int a, int b) {
        if (a > b) {
            return a;
        }
        return b;
    }

    public static int min(int a, int b) {
        if (a < b) {
            return a;
        }
        return b;
    }

    public static int absolute(int n) {
        if (n < 0) {
            return -n;
        }
        return n;
    }

    public static double average(int a, int b, int c) {
        return (a + b + c) / 3.0;
    }
}

public class EMICalculator {
    public static void main(String[] args) {
        double principal = 300000.0;
        double annualRate = 10.0;
        int months = 24;
        double monthlyRate = annualRate / 12 / 100;

        double emi = calculateEmi(principal, monthlyRate, months);
        printSummary(principal, emi, months);
    }

    public static double calculateEmi(double principal, double monthlyRate, int months) {
        double powerTerm = Math.pow(1 + monthlyRate, months);
        return principal * monthlyRate * powerTerm / (powerTerm - 1);
    }

    public static void printSummary(double principal, double emi, int months) {
        System.out.println("Principal: " + principal);
        System.out.println("Months: " + months);
        System.out.println("Monthly EMI: " + emi);
        System.out.println("Total Paid: " + (emi * months));
    }
}

public class Payroll {
    public static void main(String[] args) {
        String name = "Vikram";
        double hourlyRate = 500.0;
        double hoursWorked = 160.0;
        double taxRate = 10.0;

        double grossPay = calculateGrossPay(hourlyRate, hoursWorked);
        double tax = calculateTax(grossPay, taxRate);
        double netPay = calculateNetPay(grossPay, tax);

        printPaystub(name, grossPay, tax, netPay);
    }

    public static double calculateGrossPay(double hourlyRate, double hoursWorked) {
        return hourlyRate * hoursWorked;
    }

    public static double calculateTax(double grossPay, double taxRate) {
        return grossPay * (taxRate / 100);
    }

    public static double calculateNetPay(double grossPay, double tax) {
        return grossPay - tax;
    }

    public static void printPaystub(String name, double grossPay, double tax, double netPay) {
        System.out.println("=========================");
        System.out.println("      PAYSTUB: " + name);
        System.out.println("=========================");
        System.out.println("Gross Pay: " + grossPay);
        System.out.println("Tax:       " + tax);
        System.out.println("Net Pay:   " + netPay);
        System.out.println("=========================");
    }
}
